INSERT INTO Note ("id", "title", "content", "course", "lesson", "createdAt", "userId") VALUES ('c87bd9ef-5ef8-4074-9b6b-399d66a7ade7', '107- 形容词比较级，最高级', '<p>📌 一、比较级用法（super常用）</p><h1>👉 A + be + 比较级 + than + B</h1><p>💬 例子</p><p>I’m taller than him.</p><p>👉 我比他高</p><p>This is cheaper than that.</p><p>👉 这个比那个便宜</p><h1>👉 much / a lot + 比较级</h1><p>This is much better.</p><h2>👉 这个好很多</h2><h2>👉 越来越……</h2><h3>👉 比较级 + and + 比较级</h3><p>It’s getting better and better.</p><h2>👉 越来越好</h2><p>📌 二、最高级用法</p><p>👉 基本句型</p><p>👉 A + be + the + 最高级 + 范围</p><p>💬 例子</p><p>He is the tallest in the class.</p><p>👉 他是班里最高的</p><p>This is the best restaurant here.</p><p>👉 这是这里最好的餐厅</p>', '新概念英语', '', '2026-04-26 23:50:36.959', '00000000-0000-0000-0000-000000000001');
